{"cmd":"# Try different key names - QEMU uses specific key names
python3 << 'PYEOF'
import socket, time

def send_cmd(cmd):
    s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
    s.connect('/tmp/qemu-monitor')
    time.sleep(0.2)
    data = b''
    while True:
        try:
            chunk = s.recv(4096)
            data += chunk
            if b'(qemu)' in data:
                break
        except socket.timeout:
            break
    s.sendall((cmd + '\n').encode())
    time.sleep(0.5)
    try:
        resp = s.recv(4096)
        print(f"  {cmd} -> {resp.decode(errors='replace')}")
    except socket.timeout:
        print(f"  {cmd} -> (accepted)")
    s.close()

# Try various key names for Enter
for key in ['Return', 'enter', 'ret', 'kp_enter', 'kp_return']:
    send_cmd(f'sendkey {key}')
PYEOF"}
